INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1760-0000-0000-0000-000000000004', 'A subdivision yields {{lots:f0}} lots on a {{acres:f1}}-acre tract (including all streets and easements). Compute the GROSS density in lots per acre.', 'numeric_input', '[]'::jsonb, '0', 'Gross density divides the lot count by the entire tract acreage (streets and easements included): {{lots:f0}} / {{acres:f1}} = {{_answer}} lots/acre.', 'medium', 'c1000011-0000-0000-0000-000000000011', NULL, ARRAY['buildout','module-17','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1750-0000-0000-0000-000000000004', 0.05);
