UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A subdivision divides land into lots and blocks served by streets, ROW, and easements','Lots are sized by frontage and depth; blocks group lots between streets','ROW is dedicated land for streets/utilities; easements are limited-use rights over private lots','Good design balances buildable yield against access, drainage, utilities, and setbacks']::text[], learning_objectives=ARRAY['Define the basic components of a subdivision: lots, blocks, streets, rights-of-way, and easements','Explain how lot frontage, depth, and area drive the design and yield of a subdivision','Describe the design objectives a layout must balance: access, drainage, utilities, density, and marketability','Distinguish a right-of-way (ROW) from an easement and explain why each is reserved']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='9f32004f-0308-4c54-a042-702b4d241d33';
DELETE FROM lesson_blocks WHERE lesson_id='9f32004f-0308-4c54-a042-702b4d241d33';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Municipal platting authority is in Loc. Gov''t Code Ch. 212; county authority in Ch. 232','A city''s platting reach extends into its ETJ, not just the corporate limits','Loc. Gov''t Code 212.004 requires a plat to subdivide land in the regulated area','A county clerk may not record a plat without required approval and a tax certificate (Prop. Code 12.002)']::text[], learning_objectives=ARRAY['Identify the two principal Texas platting statutes: Local Government Code Ch. 212 (municipal) and Ch. 232 (county)','Explain the role of a municipality''s extraterritorial jurisdiction (ETJ) in subdivision control','State the rule that subdividing in a regulated area requires a plat, even for metes-and-bounds conveyances','Describe the platting-approval and recording gatekeeping unique to Texas (tax certificate; clerk''s duty)']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='cff08476-3c98-44ca-a59d-c35063701abe';
DELETE FROM lesson_blocks WHERE lesson_id='cff08476-3c98-44ca-a59d-c35063701abe';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Preliminary plat = conceptual approval; final plat = the recordable instrument','A final plat shows boundary, lots/blocks, dimensions, ROW, easements, dedication, and monuments','The RPLS certifies the plat and is responsible for monumentation','Texas subdivision-plat standards are in 22 TAC Ch. 138, with 138.93 addressing subdivision plats']::text[], learning_objectives=ARRAY['Distinguish a preliminary plat from a final plat and describe the approval sequence','List the elements a final plat must show (boundary, lots/blocks, ROW, easements, dedication, monuments)','Explain the surveyor''s monumentation duty and certification on a plat','Identify the governing TBPELS standard for subdivision plats (22 TAC Ch. 138, esp. 138.93)']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='c0d8bd65-e438-4a66-a932-ea7e76ddea3e';
DELETE FROM lesson_blocks WHERE lesson_id='c0d8bd65-e438-4a66-a932-ea7e76ddea3e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Lot area = frontage x depth for a rectangular lot; the building envelope is the lot minus setbacks','Front, side, and rear setbacks define the buildable area on each lot','Yield = number of conforming lots a tract can produce after ROW/easement take','Gross density (lots/acre) uses the whole tract; net density uses only the buildable area']::text[], learning_objectives=ARRAY['Apply minimum lot-size, frontage, and setback requirements to lay out conforming lots','Compute lot area from frontage and depth and estimate lots from net buildable area','Explain setbacks (front, side, rear) and how the building envelope is derived','Describe density and yield and compute lots per acre']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='d5b60839-89a1-49ff-a054-4deea97c0a79';
DELETE FROM lesson_blocks WHERE lesson_id='d5b60839-89a1-49ff-a054-4deea97c0a79';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Streets form a hierarchy: local -> collector -> arterial, with widening ROW','Cul-de-sac turnarounds need a minimum radius for emergency and service vehicles','Utility easements typically run along rear/side lot lines; drainage easements follow flow paths','ROW area = length x width; a turnaround bulb adds pi r^2 of paved circle']::text[], learning_objectives=ARRAY['Describe the functional street hierarchy (local, collector, arterial) and typical ROW widths','Lay out cul-de-sacs and compute the area of a circular turnaround','Place drainage and utility easements to serve every lot','Explain how street and utility layout interacts with lot yield and drainage']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='6387002b-9d9f-4f4e-bcb3-fdb1926273f1';
DELETE FROM lesson_blocks WHERE lesson_id='6387002b-9d9f-4f4e-bcb3-fdb1926273f1';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Approval by the governing authority precedes recording with the county clerk','Prop. Code 12.002 bars recording without approval and an original tax certificate','Recording the plat effects statutory dedication of streets/easements and establishes lots','A replat amends a recorded plat; a vacation cancels one — both follow statutory procedure']::text[], learning_objectives=ARRAY['Sequence the approval-then-recording process for a Texas plat','Explain the documents required to record a plat, including the tax certificate','Describe how recording creates statutory dedication and establishes lots','Define a replat and vacation of a plat and when each is used']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='09e7d13c-12bb-4019-b55c-d6139667ec4e';
DELETE FROM lesson_blocks WHERE lesson_id='09e7d13c-12bb-4019-b55c-d6139667ec4e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Real platting integrates design math, jurisdiction, and recording in one workflow','Most platting failures are jurisdictional (ETJ) or technical (non-closure, missing easements)','Lots in a recorded plat are simultaneous conveyances — excess/deficiency is apportioned, no lot is senior','A defensible plat closes mathematically, serves every lot, and clears every approval']::text[], learning_objectives=ARRAY['Apply yield, density, ROW, and lot-sizing calculations to a realistic tract','Diagnose common platting defects (non-closure, missing easements, ETJ oversight)','Resolve excess/deficiency among simultaneously created lots by proportionate measurement','Integrate design, regulatory, and recording requirements into a coherent platting workflow']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='3f3ce9de-e506-4257-b268-04d349f5b2bf';
DELETE FROM lesson_blocks WHERE lesson_id='3f3ce9de-e506-4257-b268-04d349f5b2bf';
  'eeee1750-0000-0000-0000-000000000001', 'Lot yield from gross area minus ROW and easements', 'Lot yield from gross area minus ROW and easements', 'Subdivision Design — Yield', 'Net buildable area', 'numeric_input', 'medium', 'A {{gross:f0}} sq ft tract will be platted for single-family lots. Street ROW and easements/undevelopable area together consume {{takePct:f0}}% of the tract. If the minimum lot size is {{lotSize:f0}} sq ft, estimate the maximum number of WHOLE lots (round DOWN).', 'floor((gross*(1 - takePct/100))/lotSize)', '{"decimals":0,"unit":"lots","tolerance":0.5}', '[{"name":"gross","type":"integer","min":800000,"max":2000000},{"name":"takePct","type":"integer","min":18,"max":32},{"name":"lotSize","type":"integer","min":6000,"max":12000}]'::jsonb, '[{"name":"net","formula":"gross*(1 - takePct/100)"}]'::jsonb, '[{"step_number":1,"title":"Net buildable area","formula":"gross x (1 - take%)","calculation_template":"{{gross:f0}} x (1 - {{takePct:f0}}/100) = {{net:f0}} sq ft"},{"step_number":2,"title":"Divide by lot size and round down","result_template":"floor({{net:f0}} / {{lotSize:f0}}) = {{_answer}} lots"}]'::jsonb, '{"method":"none"}'::jsonb, 'Net buildable = {{gross:f0}} x (1 - {{takePct:f0}}%) = {{net:f0}} sq ft. Dividing by the {{lotSize:f0}} sq ft lot size and rounding down gives {{_answer}} whole lots (a first-cut upper bound before fitting to a block-and-street pattern).', 'c1000011-0000-0000-0000-000000000011', ARRAY['buildout','module-17','practice']::text[], true, 'buildout:m17');
  'eeee1750-0000-0000-0000-000000000002', 'Lot area from frontage and depth', 'Lot area from frontage and depth', 'Subdivision Design — Lot geometry', 'Rectangular lot area', 'numeric_input', 'easy', 'A rectangular lot has {{w:f0}} ft of frontage and {{d:f0}} ft of depth. Compute its area in SQUARE FEET.', 'w*d', '{"decimals":0,"unit":"sq ft","tolerance":0.5}', '[{"name":"w","type":"integer","min":45,"max":90},{"name":"d","type":"integer","min":100,"max":160}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Area = frontage x depth","calculation_template":"{{w:f0}} x {{d:f0}}"},{"step_number":2,"title":"Compute","result_template":"Area = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'For a rectangular lot, area = frontage x depth = {{w:f0}} x {{d:f0}} = {{_answer}} sq ft.', 'c1000011-0000-0000-0000-000000000011', ARRAY['buildout','module-17','practice']::text[], true, 'buildout:m17');
  'eeee1750-0000-0000-0000-000000000003', 'Street right-of-way area', 'Street right-of-way area', 'Subdivision Design — Streets', 'ROW area', 'numeric_input', 'easy', 'A straight street segment is {{L:f0}} ft long within a {{wROW:f0}} ft right-of-way. Compute the ROW area of that segment in SQUARE FEET.', 'L*wROW', '{"decimals":0,"unit":"sq ft","tolerance":0.5}', '[{"name":"L","type":"integer","min":300,"max":900},{"name":"wROW","type":"integer","min":50,"max":80}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"ROW area = length x width","calculation_template":"{{L:f0}} x {{wROW:f0}}"},{"step_number":2,"title":"Compute","result_template":"ROW area = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'A rectangular street ROW segment has area = length x width = {{L:f0}} x {{wROW:f0}} = {{_answer}} sq ft.', 'c1000011-0000-0000-0000-000000000011', ARRAY['buildout','module-17','practice']::text[], true, 'buildout:m17');
  'eeee1750-0000-0000-0000-000000000004', 'Gross density in lots per acre', 'Gross density in lots per acre', 'Subdivision Design — Density', 'Lots per acre', 'numeric_input', 'medium', 'A subdivision yields {{lots:f0}} lots on a {{acres:f1}}-acre tract (including all streets and easements). Compute the GROSS density in lots per acre.', 'lots/acres', '{"decimals":2,"unit":"lots/acre","tolerance":0.05}', '[{"name":"lots","type":"integer","min":60,"max":200},{"name":"acres","type":"float","min":15,"max":50,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Gross density = lots / total acres","calculation_template":"{{lots:f0}} / {{acres:f1}}"},{"step_number":2,"title":"Compute","result_template":"Gross density = {{_answer}} lots/acre"}]'::jsonb, '{"method":"none"}'::jsonb, 'Gross density divides the lot count by the entire tract acreage (streets and easements included): {{lots:f0}} / {{acres:f1}} = {{_answer}} lots/acre.', 'c1000011-0000-0000-0000-000000000011', ARRAY['buildout','module-17','practice']::text[], true, 'buildout:m17');
COMMIT;
